const themeMediaQuery =
  typeof window.matchMedia === "function"
    ? window.matchMedia("(prefers-color-scheme: dark)")
    : null;

const automationMessages = { en: {}, "zh-CN": {} };
const loadedAutomationMessageLocales = new Set();

let currentLocale = resolveInitialLocale();
document.documentElement.lang = currentLocale;

function resolveInitialLocale() {
  const candidates = [
    readAppContextLocale(),
    ...(navigator.languages || []),
    navigator.language,
    document.documentElement.lang
  ];
  for (const candidate of candidates) {
    const locale = normalizeLocale(candidate);
    if (locale) return locale;
  }
  return "en";
}

function readAppContextLocale() {
  return normalizeAppContextLocaleValue(readAppContextValue());
}

function readAppContextValue() {
  return window.tutti?.appContext || window.tuttiAppContext || null;
}

function normalizeAppContextLocaleValue(value) {
  if (!value) return null;
  if (typeof value === "string") return value;
  if (typeof value !== "object") return null;
  if (typeof value.locale === "string") return value.locale;
  if (typeof value.language === "string") return value.language;
  return null;
}

async function readAppContextLocaleAsync() {
  const appContext = readAppContextValue();
  if (!appContext || typeof appContext !== "object") return null;
  if (typeof appContext.get === "function") {
    try {
      return normalizeAppContextLocaleValue(await appContext.get());
    } catch {
      return null;
    }
  }
  if (typeof appContext.getLocale !== "function") {
    return normalizeAppContextLocaleValue(appContext);
  }

  try {
    return normalizeAppContextLocaleValue(await appContext.getLocale());
  } catch {
    return null;
  }
}

async function syncLocaleFromAppContext() {
  await applyLocale(await readAppContextLocaleAsync());
}

async function initializeLocaleFromAppContext() {
  const locale = normalizeLocale(
    normalizeAppContextLocaleValue(await readAppContextLocaleAsync())
  );
  if (locale) {
    currentLocale = locale;
  }
}

async function applyLocale(value) {
  const locale = normalizeLocale(normalizeAppContextLocaleValue(value));
  if (!locale) return;
  if (locale === currentLocale && loadedAutomationMessageLocales.has(locale)) {
    return;
  }
  currentLocale = locale;
  document.documentElement.lang = currentLocale;
  await ensureLocaleMessages(currentLocale);
  if (state.runnerOptions.available) {
    await refreshRunnerOptionsForProvider(
      state.selectedProvider,
      collectRunnerSettings()
    );
  }
  render();
}

function initializeAppContextSync() {
  void syncLocaleFromAppContext();
  const appContext = readAppContextValue();
  if (!appContext || typeof appContext !== "object") {
    return;
  }

  if (typeof appContext.subscribe === "function") {
    appContext.subscribe((context) => {
      void applyLocale(context);
    });
    return;
  }

  if (typeof appContext.onLocaleChanged === "function") {
    appContext.onLocaleChanged((locale) => {
      void applyLocale(locale);
    });
  }
}

function normalizeAgentProviderId(value) {
  const provider = String(value || "").trim();
  return provider || null;
}

function normalizeLocale(value) {
  const next = String(value || "")
    .trim()
    .replace("_", "-")
    .toLowerCase();
  if (!next) return null;
  if (next === "zh" || next.startsWith("zh-")) return "zh-CN";
  if (next === "en" || next.startsWith("en-")) return "en";
  return null;
}

async function initializeLocaleMessages() {
  await ensureLocaleMessages(currentLocale);
  document.documentElement.lang = currentLocale;
}

async function ensureLocaleMessages(locale) {
  await loadLocaleMessages("en");
  const normalized = normalizeLocale(locale) || "en";
  if (normalized !== "en") {
    await loadLocaleMessages(normalized);
  }
}

async function loadLocaleMessages(locale) {
  const normalized = normalizeLocale(locale) || "en";
  if (loadedAutomationMessageLocales.has(normalized)) return;
  const response = await fetch(`/assets/locales/${normalized}.json`, {
    headers: { Accept: "application/json" }
  });
  if (!response.ok) {
    throw new Error(`Locale ${normalized} failed to load.`);
  }
  const messages = await response.json();
  automationMessages[normalized] =
    messages && typeof messages === "object" ? messages : {};
  loadedAutomationMessageLocales.add(normalized);
}

function hasMessage(key) {
  return Boolean(
    automationMessages[currentLocale]?.[key] || automationMessages.en[key]
  );
}

function t(key, params = {}) {
  const template =
    automationMessages[currentLocale]?.[key] ||
    automationMessages.en[key] ||
    key;
  return template.replace(/\{(\w+)\}/g, (_, name) =>
    Object.prototype.hasOwnProperty.call(params, name)
      ? params[name]
      : `{${name}}`
  );
}

