function setButtonText(button, label) {
  const textNode = [...button.childNodes].find(
    (node) => node.nodeType === 3 && node.textContent.trim()
  );
  if (textNode) {
    textNode.textContent = ` ${label}`;
    return;
  }
  button.append(document.createTextNode(label));
}

async function api(path, options = {}) {
  const response = await fetch(path, {
    ...options,
    headers: {
      "Content-Type": "application/json",
      ...(options.headers || {})
    }
  });
  const body = await response.json();
  if (!response.ok) {
    throw new Error(body.error || t("request.failed"));
  }
  return body;
}

async function load() {
  try {
    state.isLoadingAutomations = true;
    renderAppHeader();
    renderList();

    const contextRequest = api("/api/context");
    const automationsRequest = api("/api/automations");
    const runnerOptionsRequest = api(runnerOptionsApiPath());
    const cwdOptionsRequest = api("/api/cwd-options");

    const automations = await automationsRequest;
    state.automations = automations.automations;
    state.isLoadingAutomations = false;
    renderAppHeader();
    renderList();
    renderInbox();
    syncActiveRunRefresh();

    const [context, runnerOptions, cwdOptions] = await Promise.all([
      contextRequest,
      runnerOptionsRequest,
      cwdOptionsRequest
    ]);
    state.context = context;
    state.runnerOptions = normalizeRunnerOptions(runnerOptions);
    state.cwdOptions = cwdOptions;
    renderTemplateList();
    renderScheduleFrequencyOptions();
    renderRunnerOptions();
    hydrateWorkspaceSelectors();
    renderInbox();
    syncActiveRunRefresh();
  } catch (error) {
    state.isLoadingAutomations = false;
    renderList();
    showError(error.message);
  }
}

