els.configDialog.addEventListener("click", (event) => {
  if (event.target === els.configDialog) closeConfigDialog();
});
els.deleteConfirmDialog.addEventListener("click", (event) => {
  if (event.target === els.deleteConfirmDialog) closeDeleteConfirmDialog();
});

document.addEventListener("keydown", (event) => {
  if (event.key !== "Escape") return;
  if (isDetailInfoPopoverOpen()) {
    closeDetailInfoPopover();
    return;
  }
  if (hasOpenRunnerMenu()) {
    closeRunnerMenus();
    return;
  }
  if (!els.deleteConfirmDialog.classList.contains("hidden")) {
    closeDeleteConfirmDialog();
    return;
  }
  if (!els.configDialog.classList.contains("hidden")) {
    closeConfigDialog();
    return;
  }
  if (state.inboxAutomationId) closeInbox();
});

document.addEventListener("click", () => {
  closeMoreMenus();
  closeCwdMenu();
  closeRunnerMenus();
  closeSchedulePanel();
  closeDetailInfoPopover();
});
window.addEventListener("resize", () => {
  syncInboxFilterIndicator();
  syncTemplateScrollControls();
  if (isNarrowDetailLayout()) {
    queueDetailInfoPopoverPosition();
  } else {
    closeDetailInfoPopover({ immediate: true });
  }
});

void boot();

async function boot() {
  initializeThemeSync();
  await initializeLocaleFromAppContext();
  await initializeLocaleMessages();
  renderStaticCopy();
  renderStaticIcons(document);
  initializeCustomScrollbars();
  renderAppHeader();
  renderList();
  initializeAppContextSync();
  await load();
}
